#include <bits/stdc++.h>
using namespace std;
int d[4][2]={{-1,0},{1,0},{0,-1},{0,1}};
int m,des[310][310],step[310][310];
int bfs(){
    queue<int> x,y;
    x.push(0),y.push(0),step[0][0]=1;
    if(des[0][0]>1<<30)
        return 0;
    while(x.size()){
        int fx=x.front(),fy=y.front();
        x.pop(),y.pop();
        for(int i=0;i<4;i++){
            int xx=fx+d[i][0],yy=fy+d[i][1];
            if(xx>=0 && yy>=0 && xx<303 && yy<303 && !step[xx][yy] && des[xx][yy]>step[fx][fy]){
                step[xx][yy]=step[fx][fy]+1,x.push(xx),y.push(yy);
                if(des[xx][yy]>1<<30)
                    return step[xx][yy]-1;
            }
        }
    }
    return -1;
}
int main(){
    scanf("%d",&m);
    memset(des,127,sizeof(des));
    for(int i=1;i<=m;i++){
        int x,y,t;
        scanf("%d%d%d",&x,&y,&t);
        des[x][y]=min(des[x][y],t);
        for(int j=0;j<4;j++){
            int xx=x+d[j][0],yy=y+d[j][1];
            if(xx>=0 && yy>=0)
                des[xx][yy]=min(des[xx][yy],t);
        }
    }
    printf("%d",bfs());
    return 0;
}
